const { ethers } = require("ethers");

const provider = new ethers.providers.Web3Provider(window.ethereum);
const signer = provider.getSigner();

const tokenAAddress = "0xYourTokenAAddress"; // Replace with your token A address
const tokenBAddress = "0xYourTokenBAddress"; // Replace with your token B address
const dexAddress = "0xYourDexAddress"; // Replace with your DEX contract address

const tokenA = new ethers.Contract(tokenAAddress, [
    "function approve(address spender, uint256 amount) public returns (bool)",
    "function balanceOf(address owner) public view returns (uint256)"
], signer);

const tokenB = new ethers.Contract(tokenBAddress, [
    "function balanceOf(address owner) public view returns (uint256)"
], signer);

const dex = new ethers.Contract(dexAddress, [
    "function swap(address tokenA, address tokenB, uint256 amountA, uint256 minAmountB) public"
], signer);

async function approveTokens() {
    const maxUint256 = ethers.constants.MaxUint256;
    const tx = await tokenA.approve(dexAddress, maxUint256);
    await tx.wait();
    console.log("Approval successful for Token A");
}

async function swapTokens(amountA, minAmountB) {
    const tx = await dex.swap(tokenAAddress, tokenBAddress, amountA, minAmountB);
    await tx.wait();
    console.log("Swap successful");
}

async function getBalances() {
    const userAddress = await signer.getAddress();
    const balanceA = await tokenA.balanceOf(userAddress);
    const balanceB = await tokenB.balanceOf(userAddress);
    console.log(`Balance of Token A: ${ethers.utils.formatEther(balanceA)}`);
    console.log(`Balance of Token B: ${ethers.utils.formatEther(balanceB)}`);
}

// Example usage
